import React, { useEffect, useState } from "react";
import axios from "axios";
import Api from "../api/Api";

function AssignLocation() {
  const [locations, setLocations] = useState([]);
  const [supervisors, setSupervisors] = useState([]);
  const [selectedSupervisor, setSelectedSupervisor] = useState("");
  const [selectedLocations, setSelectedLocations] = useState([]);


const [selectedZone, setSelectedZone] =
  useState("");
  useEffect(() => {
    fetchUsers();
    fetchLocations();
  }, []);
const assignZone = async () => {
  try {

    if (!selectedSupervisor) {
      return alert("Select Supervisor");
    }

    if (!selectedZone) {
      return alert("Select Zone");
    }

    await axios.put(
      Api.assign_Zone,
      {
        supervisorId: selectedSupervisor,
        zone: selectedZone,
      }
    );

    alert("Zone Assigned Successfully");

    setSelectedSupervisor("");
    setSelectedZone("");

  } catch (err) {

    console.log(err.response?.data);

    alert("Assignment Failed");
  }
};
  const fetchUsers = async () => {
    try {
      const res = await axios.get(Api.get_All_User);

      const onlySupervisors = res.data.filter(
        (u) => u.role === "supervisor"
      );

      setSupervisors(onlySupervisors);
    } catch (err) {
      console.log(err);
    }
  };

 const fetchLocations = async () => {
  try {
    const res = await axios.get(
      Api.get_All_Locations
    );

    setLocations(res.data);

  } catch (err) {
    console.log(err);
  }
};

  const assignLocations = async () => {
    try {
      if (!selectedSupervisor) {
        return alert("Select Supervisor");
      }

      if (selectedLocations.length === 0) {
        return alert("Select Locations");
      }

      await axios.put(
        Api.assign_Supervisor,
        {
          supervisorId: selectedSupervisor,
          locationIds: selectedLocations,
        }
      );

      alert("Locations Assigned Successfully");

      setSelectedSupervisor("");
      setSelectedLocations([]);

      fetchLocations(); // assigned locations remove ho jayenge

    } catch (err) {
      console.log(err.response?.data || err);
      alert("Assignment Failed");
    }
  };

  return (
    <div className="min-h-screen bg-green-50 p-6">

      <div className="max-w-5xl mx-auto bg-white rounded-2xl shadow-sm p-6">

        <h2 className="text-2xl font-bold text-green-900 mb-5">
          Assign Hostels To Supervisor
        </h2>

    <select
  className="border p-3 rounded w-full mb-4"
  value={selectedZone}
  onChange={(e) =>
    setSelectedZone(e.target.value)
  }
>
  <option value="">
    Select Zone
  </option>

  <option value="Hostel Zone 1">
    Hostel Zone 1
  </option>

  <option value="Hostel Zone 2">
    Hostel Zone 2
  </option>

  <option value="Academic Zone">
    Academic Zone
  </option>

  <option value="Colony Zone">
    Colony Zone
  </option>

</select>

        <div className="grid md:grid-cols-3 gap-2">

          {locations.map((loc) => (
            <label
              key={loc._id}
              className="border p-3 rounded cursor-pointer"
            >
              <input
                type="checkbox"
                className="mr-2"
                checked={selectedLocations.includes(
                  loc._id
                )}
                onChange={(e) => {
                  if (e.target.checked) {
                    setSelectedLocations((prev) => [
                      ...prev,
                      loc._id,
                    ]);
                  } else {
                    setSelectedLocations((prev) =>
                      prev.filter(
                        (id) => id !== loc._id
                      )
                    );
                  }
                }}
              />

              {loc.location}
            </label>
          ))}

        </div>

        <button
          onClick={assignLocations}
          className="bg-green-800 text-white px-5 py-3 rounded mt-4"
        >
          Assign Locations
        </button>

      </div>

    </div>
  );
}

export default AssignLocation;
